def trimmed_mean(nums):
    if not nums:
        return None

    nums.sort()
    n = len(nums)
    median = nums[(n - 1) // 2]
    min_index, max_index = 0, n - 1

    while min_index < max_index:
        if nums[min_index] == min(nums):
            del nums[min_index]
            break
        min_index += 1

    while min_index < max_index:
        if nums[max_index] == max(nums):
            del nums[max_index]
            break
        max_index -= 1

    return sum(nums) / (n - 2)
